body:
This PR reworks hardware lowering to be based on the new `pipeline.stage` operation introduced in https://github.com/llvm/circt/pull/5246.

Two lowering options are available, inline and outline lowering.

Given an input:
```mlir
hw.module @testMultiple(%arg0 : i32, %arg1 : i32, %go : i1, %clk : i1, %rst : i1) -> (out: i32) {
  %0 = pipeline.pipeline(%arg0, %arg1, %go) clock %clk reset %rst : (i32, i32, i1) -> i32 {
  ^bb0(%arg0_0: i32, %arg1_1: i32, %arg2: i1):
    %output, %valid = pipeline.stage ins %arg0_0, %arg1_1 enable %arg2 : (i32, i32) -> (i32) {
    ^bb0(%arg3: i32, %arg4: i32, %arg5: i1):
      %2 = comb.add %arg3, %arg4 : i32
      pipeline.stage.return regs %2 valid %arg5 : (i32)
    }
    pipeline.return %output valid %valid : i32
  }
  %1 = pipeline.pipeline(%0, %0, %go) clock %clk reset %rst : (i32, i32, i1) -> i32 {
  ^bb0(%arg0_0: i32, %arg1_1: i32, %arg2: i1):
    %output, %valid = pipeline.stage ins %arg0_0, %arg1_1 enable %arg2 : (i32, i32) -> (i32) {
    ^bb0(%arg3: i32, %arg4: i32, %arg5: i1):
      %2 = comb.add %arg3, %arg4 : i32
      pipeline.stage.return regs %2 valid %arg5 : (i32)
    }
    pipeline.return %output valid %valid : i32
  }
  hw.output %1 : i32
}
```

## Inline lowering
All operations are inlined directly into the parent scope of the `pipeline.pipeline`:

```mlir
  hw.module @testMultiple(%arg0: i32, %arg1: i32, %go: i1, %clk: i1, %rst: i1) -> (out: i32) {
    %0 = comb.add %arg0, %arg1 : i32
    %p0_s0_reg0 = seq.compreg %0, %clk : i32
    %p0_s0_valid = seq.compreg %go, %clk : i1
    %1 = comb.add %p0_s0_reg0, %p0_s0_reg0 : i32
    %p1_s0_reg0 = seq.compreg %1, %clk : i32
    %p1_s0_valid = seq.compreg %go, %clk : i1
    hw.output %p1_s0_reg0 : i32
  }
```

## Outline lowering
All stages and the pipeline itself are outlined into separate modules. The pipeline will contain instantiations of the stages of which it is comprised. There will be a single instantiation of the pipeline module at the `pipeline.pipeline` location.

```mlir
  hw.module @testMultiple_p0(%in0: i32, %in1: i32, %in2: i1, %clk: i1, %rst: i1) -> (out0: i32) {
    %testMultiple_p0_s0.out0, %testMultiple_p0_s0.valid = hw.instance "testMultiple_p0_s0" @testMultiple_p0_s0(in0: %in0: i32, in1: %in1: i32, enable: %in2: i1, clk: %clk: i1, rst: %rst: i1) -> (out0: i32, valid: i1)
    hw.output %testMultiple_p0_s0.out0 : i32
  }
  hw.module @testMultiple_p0_s0(%in0: i32, %in1: i32, %enable: i1, %clk: i1, %rst: i1) -> (out0: i32, valid: i1) {
    %0 = comb.add %in0, %in1 : i32
    %s0_reg0 = seq.compreg %0, %clk : i32
    %s0_valid = seq.compreg %enable, %clk : i1
    hw.output %s0_reg0, %s0_valid : i32, i1
  }
  hw.module @testMultiple_p1(%in0: i32, %in1: i32, %in2: i1, %clk: i1, %rst: i1) -> (out0: i32) {
    %testMultiple_p1_s0.out0, %testMultiple_p1_s0.valid = hw.instance "testMultiple_p1_s0" @testMultiple_p1_s0(in0: %in0: i32, in1: %in1: i32, enable: %in2: i1, clk: %clk: i1, rst: %rst: i1) -> (out0: i32, valid: i1)
    hw.output %testMultiple_p1_s0.out0 : i32
  }
  hw.module @testMultiple_p1_s0(%in0: i32, %in1: i32, %enable: i1, %clk: i1, %rst: i1) -> (out0: i32, valid: i1) {
    %0 = comb.add %in0, %in1 : i32
    %s0_reg0 = seq.compreg %0, %clk : i32
    %s0_valid = seq.compreg %enable, %clk : i1
    hw.output %s0_reg0, %s0_valid : i32, i1
  }
  hw.module @testMultiple(%arg0: i32, %arg1: i32, %go: i1, %clk: i1, %rst: i1) -> (out: i32) {
    %testMultiple_p0.out0 = hw.instance "testMultiple_p0" @testMultiple_p0(in0: %arg0: i32, in1: %arg1: i32, in2: %go: i1, clk: %clk: i1, rst: %rst: i1) -> (out0: i32)
    %testMultiple_p1.out0 = hw.instance "testMultiple_p1" @testMultiple_p1(in0: %testMultiple_p0.out0: i32, in1: %testMultiple_p0.out0: i32, in2: %go: i1, clk: %clk: i1, rst: %rst: i1) -> (out0: i32)
    hw.output %testMultiple_p1.out0 : i32
  }
```
